function showPosts(s){let t="";s&&0!==s.length||(t="<h1>No results</h1>"),s.forEach(s=>{t+=`<div class="single-post-area style-2">\n                        <div class="row align-items-center">\n                            <div class="col-12 col-md-6">\n                                <div class="post-thumbnail">\n                                    <img src="/img/${s.thumbnail}" alt="" class="img-fluid"/>\n                                </div>\n                            </div>\n                            <div class="col-12 col-md-6">\n                                <div class="post-content mt-0">\n                                    <a href="/posts/${s.file}" class="post-title mb-2">${s.title}</a>\n                                    <div class="post-meta d-flex align-items-center mb-2">\n                                        <span class="post-author">By Jonathan Peterson</span>\n                                        <i class="far fa-circle" aria-hidden="true"></i>\n                                        <span class="post-date">${s.postDate}</span>\n                                    </div>\n                                    <p class="mb-2">${s.excerpt}</p>\n                                </div>\n                            </div>\n                        </div>\n                    </div>`}),document.getElementById("post-container").innerHTML=t}const urlParams=new URLSearchParams(window.location.search),term=urlParams.get("search");function onLinkClick(s){window.location.href=s.target.href}term&&fetch("/posts/posts.json").then(s=>s.json()).then(s=>{showPosts(s.filter(s=>s.title.includes(term)||s.body.includes(term)))}),[...document.querySelectorAll(".vizew-pager .post-title")].forEach(s=>s.addEventListener("click",onLinkClick));